1	import { Request, Response, NextFunction } from 'express';
2	import { Role } from '../types/enums';
3	import { BadRequestError } from '../lib/errors';
4	
5	export function dealershipScope(req: Request, _res: Response, next: NextFunction): void {
6	  if (!req.user) {
7	    next();
8	    return;
9	  }
10	
11	  if (req.user.role === Role.ADMIN) {
12	    const headerDealershipId = req.headers['x-dealership-id'] as string;
13	    if (headerDealershipId) {
14	      req.scope = { dealershipId: headerDealershipId };
15	    }
16	    next();
17	    return;
18	  }
19	
20	  if (!req.user.dealershipId) {
21	    next(new BadRequestError('User is not associated with a dealership'));
22	    return;
23	  }
24	
25	  req.scope = { dealershipId: req.user.dealershipId };
26	  next();
27	}
