1	import { Request, Response, NextFunction } from 'express';
2	import { AppError } from '../lib/errors';
3	import logger from '../lib/logger';
4	
5	export function errorHandler(
6	  err: Error,
7	  req: Request,
8	  res: Response,
9	  _next: NextFunction
10	): void {
11	  if (err instanceof AppError) {
12	    res.status(err.code).json({ code: err.code, msg: err.msg });
13	    return;
14	  }
15	
16	  if (err.name === 'ValidationError') {
17	    res.status(422).json({ code: 422, msg: err.message });
18	    return;
19	  }
20	
21	  if (err.name === 'CastError') {
22	    res.status(400).json({ code: 400, msg: 'Invalid ID format' });
23	    return;
24	  }
25	
26	  if ((err as any).code === 11000) {
27	    res.status(409).json({ code: 409, msg: 'Duplicate entry' });
28	    return;
29	  }
30	
31	  logger.error(
32	    { error: err.message, stack: err.stack, requestId: req.requestId },
33	    'Unhandled error'
34	  );
35	
36	  res.status(500).json({ code: 500, msg: 'Internal server error' });
37	}
