1	import { Request, Response, NextFunction } from 'express';
2	import { verifyHmac } from '../lib/crypto';
3	import { UnauthorizedError, ConflictError } from '../lib/errors';
4	import { getRedisClient } from '../config/redis';
5	import config from '../config';
6	import logger from '../lib/logger';
7	
8	export async function hmacVerify(
9	  req: Request,
10	  _res: Response,
11	  next: NextFunction
12	): Promise<void> {
13	  try {
14	    const signature = req.headers['x-hmac-signature'] as string;
15	    const timestamp = req.headers['x-timestamp'] as string;
16	
17	    if (!signature || !timestamp) {
18	      throw new UnauthorizedError('Missing HMAC signature or timestamp');
19	    }
20	
21	    const now = Date.now();
22	    const requestTime = new Date(timestamp).getTime();
23	    const drift = Math.abs(now - requestTime) / 1000;
24	
25	    if (drift > config.hmacWindowSeconds) {
26	      throw new UnauthorizedError('Request timestamp outside acceptable window');
27	    }
28	
29	    const body = JSON.stringify(req.body) || '';
30	
31	    const valid = verifyHmac(
32	      signature,
33	      req.method,
34	      req.originalUrl,
35	      body,
36	      timestamp,
37	      config.hmacSecret
38	    );
39	
40	    if (!valid) {
41	      throw new UnauthorizedError('Invalid HMAC signature');
42	    }
43	
44	    const redis = getRedisClient();
45	    const nonceKey = `hmac:nonce:${signature}`;
46	    const exists = await redis.exists(nonceKey);
47	
48	    if (exists) {
49	      throw new ConflictError('Replay detected: request already processed');
50	    }
51	
52	    await redis.setex(nonceKey, config.hmacWindowSeconds + 10, '1');
53	
54	    next();
55	  } catch (error) {
56	    next(error);
57	  }
58	}
