52	function resolveAccountId(req: Request): string {
53	  if (req.query.accountId) return req.query.accountId as string;
54	  const role = req.user!.role;
55	  if (role === 'buyer') return `buyer:${req.user!.id}`;
56	  const dealershipId = req.scope?.dealershipId || req.user!.dealershipId;
57	  if (dealershipId && (role === 'dealership_staff' || role === 'finance_reviewer')) {
58	    return `dealership:${dealershipId}`;
59	  }
60	  if (role === 'admin' && req.scope?.dealershipId) {
61	    return `dealership:${req.scope.dealershipId}`;
62	  }
63	  return `user:${req.user!.id}`;
64	}
