99	export async function refreshTokens(refreshToken: string) {
100	  try {
101	    const decoded = jwt.verify(refreshToken, config.jwtRefreshSecret) as any;
102	    const user = await User.findById(decoded.id);
103	
104	    if (!user || user.refreshToken !== refreshToken || !user.isActive) {
105	      throw new UnauthorizedError('Invalid refresh token');
106	    }
107	
108	    const tokens = generateTokens(user);
109	    user.refreshToken = tokens.refreshToken;
110	    await user.save();
111	
112	    return tokens;
113	  } catch {
114	    throw new UnauthorizedError('Invalid refresh token');
115	  }
