44	  const experiment = await Experiment.findById(experimentId);
45	  if (!experiment) throw new NotFoundError('Experiment not found');
46	
47	  if (experiment.status !== ExperimentStatus.ACTIVE) {
48	    return { variant: experiment.variants[0]?.key || 'control', isDefault: true };
49	  }
50	
51	  let assignment = await ExperimentAssignment.findOne({ experimentId, userId });
52	  if (assignment) {
53	    return { variant: assignment.variant, isDefault: false };
54	  }
55	
56	  const totalWeight = experiment.variants.reduce((sum, v) => sum + v.weight, 0);
57	  let random = Math.random() * totalWeight;
58	  let selectedVariant = experiment.variants[0].key;
59	
60	  for (const variant of experiment.variants) {
61	    random -= variant.weight;
62	    if (random <= 0) {
63	      selectedVariant = variant.key;
64	      break;
65	    }
66	  }
67	
68	  assignment = await ExperimentAssignment.create({
69	    experimentId,
70	    userId,
