3	let synonymCache: Map<string, Map<string, string[]>> | null = null;
4	let cacheTimestamp = 0;
5	const CACHE_TTL = 60000;
6	
7	async function loadSynonyms(): Promise<Map<string, Map<string, string[]>>> {
8	  const now = Date.now();
9	  if (synonymCache && now - cacheTimestamp < CACHE_TTL) {
10	    return synonymCache;
11	  }
12	
13	  const synonyms = await Synonym.find({});
14	  const cache = new Map<string, Map<string, string[]>>();
15	
16	  for (const syn of synonyms) {
17	    if (!cache.has(syn.field)) {
18	      cache.set(syn.field, new Map());
19	    }
20	    const fieldMap = cache.get(syn.field)!;
21	
22	    fieldMap.set(syn.canonical.toLowerCase(), syn.aliases.map((a) => a.toLowerCase()));
23	
24	    for (const alias of syn.aliases) {
25	      fieldMap.set(alias.toLowerCase(), [syn.canonical.toLowerCase()]);
26	    }
27	  }
28	
29	  synonymCache = cache;
30	  cacheTimestamp = now;
31	  return cache;
32	}
33	
34	export async function expandSynonyms(
35	  term: string,
36	  field: string = 'make'
37	): Promise<string[]> {
38	  const cache = await loadSynonyms();
39	  const fieldMap = cache.get(field);
40	  if (!fieldMap) return [term];
41	
42	  const lowerTerm = term.toLowerCase();
43	  const expansions = fieldMap.get(lowerTerm);
44	  if (!expansions) return [term];
45	
46	  return [term, ...expansions];
47	}
48	
49	export function clearSynonymCache(): void {
50	  synonymCache = null;
51	  cacheTimestamp = 0;
