4	const MAGIC_BYTES: Record<string, Buffer> = {
5	  'application/pdf': Buffer.from([0x25, 0x50, 0x44, 0x46]),
6	  'image/jpeg': Buffer.from([0xff, 0xd8, 0xff]),
7	  'image/png': Buffer.from([0x89, 0x50, 0x4e, 0x47]),
