10	export function validateFileType(buffer: Buffer, declaredMime: string): string {
11	  for (const [mime, magic] of Object.entries(MAGIC_BYTES)) {
12	    if (buffer.subarray(0, magic.length).equals(magic)) {
13	      if (mime !== declaredMime) {
14	        throw new BadRequestError(
15	          `File type mismatch: declared ${declaredMime} but detected ${mime}`
16	        );
17	      }
18	      return mime;
19	    }
20	  }
21	  throw new BadRequestError('Unsupported file type. Allowed: PDF, JPG, PNG');
22	}
