13	  method: PaymentMethod;
14	  amount: number;
15	  idempotencyKey: string;
16	  metadata?: Record<string, any>;
17	}
18	
19	export async function processPayment(input: PaymentInput) {
20	  const existing = await Payment.findOne({ idempotencyKey: input.idempotencyKey });
21	  if (existing) return existing;
22	
23	  const invoice = await Invoice.findById(input.invoiceId);
24	  if (!invoice) throw new NotFoundError('Invoice not found');
25	  if (invoice.status === InvoiceStatus.PAID) {
26	    throw new BadRequestError('Invoice already paid');
27	  }
28	
29	  if (input.amount !== invoice.total) {
30	    throw new BadRequestError(
31	      `Payment amount (${input.amount}) does not match invoice total (${invoice.total})`
32	    );
33	  }
34	
35	  const order = await Order.findById(input.orderId);
36	  if (!order) throw new NotFoundError('Order not found');
37	
38	  const payment = new Payment({
39	    dealershipId: input.dealershipId,
40	    orderId: input.orderId,
41	    invoiceId: input.invoiceId,
42	    method: input.method,
43	    amount: input.amount,
44	    status: PaymentStatus.COMPLETED,
45	    adapterUsed: null,
46	    metadata: input.metadata || {},
47	    idempotencyKey: input.idempotencyKey,
48	  });
49	
50	  await payment.save();
51	
52	  await recordTransaction({
53	    dealershipId: input.dealershipId,
54	    debitAccountId: `buyer:${order.buyerId}`,
55	    creditAccountId: `dealership:${input.dealershipId}`,
56	    amount: input.amount,
57	    referenceType: 'payment',
58	    referenceId: payment._id.toString(),
59	    description: `Payment for order ${order.orderNumber}`,
60	    idempotencyKey: `payment-${payment._id}`,
61	  });
62	
63	  invoice.status = InvoiceStatus.PAID;
64	  await invoice.save();
65	
66	  logger.info(
67	    { paymentId: payment._id, orderId: input.orderId, amount: input.amount, method: input.method },
68	    'Payment processed'
69	  );
70	
71	  return payment;
72	}
