12	export async function recordTransaction(params: {
13	  dealershipId: string;
14	  debitAccountId: string;
15	  creditAccountId: string;
16	  amount: number;
17	  referenceType: 'payment' | 'refund' | 'adjustment' | 'deposit';
18	  referenceId: string;
19	  description: string;
20	  idempotencyKey: string;
21	}) {
22	  const existing = await WalletTransaction.findOne({
23	    idempotencyKey: `${params.idempotencyKey}-debit`,
24	  });
25	  if (existing) return existing;
26	
27	  const session = await mongoose.startSession();
28	
29	  try {
30	    let debitTx: any;
31	    let creditTx: any;
32	
33	    await session.withTransaction(async () => {
34	      const debitBalance = await WalletBalance.findOneAndUpdate(
35	        { accountId: params.debitAccountId },
36	        {
37	          $inc: { balance: -params.amount },
38	          $setOnInsert: {
39	            dealershipId: params.dealershipId,
40	            currency: 'USD',
41	          },
42	        },
43	        { new: true, upsert: true, session }
44	      );
45	
46	      debitTx = await WalletTransaction.create(
47	        [
48	          {
49	            dealershipId: params.dealershipId,
50	            accountId: params.debitAccountId,
51	            type: 'debit',
52	            amount: params.amount,
53	            referenceType: params.referenceType,
54	            referenceId: params.referenceId,
55	            balanceAfter: debitBalance!.balance,
56	            description: params.description,
57	            idempotencyKey: `${params.idempotencyKey}-debit`,
58	          },
59	        ],
60	        { session }
61	      );
62	
63	      const creditBalance = await WalletBalance.findOneAndUpdate(
64	        { accountId: params.creditAccountId },
65	        {
66	          $inc: { balance: params.amount },
67	          $setOnInsert: {
68	            dealershipId: params.dealershipId,
69	            currency: 'USD',
70	          },
71	        },
72	        { new: true, upsert: true, session }
73	      );
74	
75	      creditTx = await WalletTransaction.create(
76	        [
77	          {
78	            dealershipId: params.dealershipId,
79	            accountId: params.creditAccountId,
80	            type: 'credit',
81	            amount: params.amount,
82	            referenceType: params.referenceType,
83	            referenceId: params.referenceId,
84	            balanceAfter: creditBalance!.balance,
85	            description: params.description,
86	            idempotencyKey: `${params.idempotencyKey}-credit`,
87	          },
88	        ],
89	        { session }
90	      );
91	    });
92	
93	    logger.info(
94	      { debitAccount: params.debitAccountId, creditAccount: params.creditAccountId, amount: params.amount },
95	      'Ledger transaction recorded'
96	    );
97	
98	    return { debit: debitTx[0], credit: creditTx[0] };
99	  } finally {
100	    await session.endSession();
101	  }
102	}
