1	import crypto from 'crypto';
2	import { EncryptionKey } from '../../models/encryption-key.model';
3	import { encrypt, decrypt, EncryptedData } from '../../lib/crypto';
4	import config from '../../config';
5	import logger from '../../lib/logger';
6	
7	function getMasterKey(): Buffer {
8	  return Buffer.from(config.masterEncryptionKey, 'hex');
9	}
10	
11	export async function getActiveKey(): Promise<{ key: Buffer; keyId: string }> {
12	  let activeKey = await EncryptionKey.findOne({ status: 'active' });
13	
14	  if (!activeKey) {
15	    const dek = crypto.randomBytes(32);
16	    const masterKey = getMasterKey();
17	    const iv = crypto.randomBytes(16);
18	    const cipher = crypto.createCipheriv('aes-256-gcm', masterKey, iv);
19	    let encrypted = cipher.update(dek.toString('hex'), 'utf8', 'hex');
20	    encrypted += cipher.final('hex');
21	    const tag = cipher.getAuthTag().toString('hex');
22	
23	    activeKey = await EncryptionKey.create({
24	      keyId: crypto.randomUUID(),
25	      encryptedKey: `${iv.toString('hex')}:${encrypted}:${tag}`,
26	      algorithm: 'aes-256-gcm',
27	      status: 'active',
28	    });
29	
30	    logger.info({ keyId: activeKey.keyId }, 'Initial encryption key created');
31	  }
32	
33	  const [ivHex, encryptedHex, tagHex] = activeKey.encryptedKey.split(':');
34	  const masterKey = getMasterKey();
35	  const decipher = crypto.createDecipheriv(
36	    'aes-256-gcm',
37	    masterKey,
38	    Buffer.from(ivHex, 'hex')
39	  );
40	  decipher.setAuthTag(Buffer.from(tagHex, 'hex'));
41	  let dekHex = decipher.update(encryptedHex, 'hex', 'utf8');
42	  dekHex += decipher.final('utf8');
43	
44	  return { key: Buffer.from(dekHex, 'hex'), keyId: activeKey.keyId };
45	}
46	
47	export async function getKeyById(keyId: string): Promise<Buffer> {
48	  const keyRecord = await EncryptionKey.findOne({ keyId });
49	  if (!keyRecord) throw new Error(`Encryption key ${keyId} not found`);
50	
51	  const [ivHex, encryptedHex, tagHex] = keyRecord.encryptedKey.split(':');
52	  const masterKey = getMasterKey();
53	  const decipher = crypto.createDecipheriv(
54	    'aes-256-gcm',
55	    masterKey,
56	    Buffer.from(ivHex, 'hex')
57	  );
58	  decipher.setAuthTag(Buffer.from(tagHex, 'hex'));
59	  let dekHex = decipher.update(encryptedHex, 'hex', 'utf8');
60	  dekHex += decipher.final('utf8');
61	
62	  return Buffer.from(dekHex, 'hex');
63	}
64	
65	export async function encryptValue(plaintext: string): Promise<EncryptedData> {
66	  const { key, keyId } = await getActiveKey();
67	  return encrypt(plaintext, key, keyId);
68	}
69	
70	export async function decryptValue(data: EncryptedData): Promise<string> {
71	  const key = await getKeyById(data.keyVersion);
72	  return decrypt(data, key);
73	}
74	
75	export async function rotateKey(): Promise<string> {
76	  await EncryptionKey.updateMany({ status: 'active' }, { status: 'rotated', rotatedAt: new Date() });
77	
78	  const dek = crypto.randomBytes(32);
79	  const masterKey = getMasterKey();
80	  const iv = crypto.randomBytes(16);
81	  const cipher = crypto.createCipheriv('aes-256-gcm', masterKey, iv);
82	  let encrypted = cipher.update(dek.toString('hex'), 'utf8', 'hex');
83	  encrypted += cipher.final('hex');
84	  const tag = cipher.getAuthTag().toString('hex');
85	
86	  const newKey = await EncryptionKey.create({
87	    keyId: crypto.randomUUID(),
88	    encryptedKey: `${iv.toString('hex')}:${encrypted}:${tag}`,
89	    algorithm: 'aes-256-gcm',
90	    status: 'active',
91	  });
92	
93	  logger.info({ keyId: newKey.keyId }, 'Encryption key rotated');
94	  return newKey.keyId;
95	}
