1	import { PermissionOverride } from '../models/permission-override.model';
2	import { Role, PermissionEffect } from '../types/enums';
3	
4	const DEFAULT_PERMISSIONS: Record<string, Record<string, string[]>> = {
5	  document: {
6	    [Role.ADMIN]: ['read', 'write', 'delete', 'download', 'share', 'submit', 'approve'],
7	    [Role.DEALERSHIP_STAFF]: ['read', 'write', 'delete', 'download', 'share', 'submit'],
8	    [Role.FINANCE_REVIEWER]: ['read', 'download', 'submit', 'approve'],
9	    [Role.BUYER]: ['read', 'download'],
10	  },
11	  order: {
12	    [Role.ADMIN]: ['read', 'write', 'delete'],
13	    [Role.DEALERSHIP_STAFF]: ['read', 'write'],
14	    [Role.FINANCE_REVIEWER]: ['read'],
15	    [Role.BUYER]: ['read'],
16	  },
17	};
18	
19	export async function checkPermission(
20	  userId: string,
21	  role: string,
22	  dealershipId: string,
23	  resource: string,
24	  resourceId: string | null,
25	  action: string,
26	  sensitiveFlag: boolean = false
27	): Promise<boolean> {
28	  if (role === Role.ADMIN) return true;
29	
30	  if (sensitiveFlag && role !== Role.FINANCE_REVIEWER && role !== Role.ADMIN) {
31	    const override = await PermissionOverride.findOne({
32	      dealershipId,
33	      resource,
34	      resourceId,
35	      userId,
36	      actions: action,
37	      effect: PermissionEffect.ALLOW,
38	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
39	    });
40	    return !!override;
41	  }
42	
43	  if (resourceId) {
44	    const userOverride = await PermissionOverride.findOne({
45	      dealershipId,
46	      resource,
47	      resourceId,
48	      userId,
49	      actions: action,
50	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
51	    });
52	    if (userOverride) return userOverride.effect === PermissionEffect.ALLOW;
53	
54	    const roleOverride = await PermissionOverride.findOne({
55	      dealershipId,
56	      resource,
57	      resourceId,
58	      role,
59	      userId: null,
60	      actions: action,
61	      $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
62	    });
63	    if (roleOverride) return roleOverride.effect === PermissionEffect.ALLOW;
64	  }
65	
66	  const userDealershipOverride = await PermissionOverride.findOne({
67	    dealershipId,
68	    resource,
69	    resourceId: null,
70	    userId,
71	    actions: action,
72	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
73	  });
74	  if (userDealershipOverride) return userDealershipOverride.effect === PermissionEffect.ALLOW;
75	
76	  const roleDealershipOverride = await PermissionOverride.findOne({
77	    dealershipId,
78	    resource,
79	    resourceId: null,
80	    role,
81	    userId: null,
82	    actions: action,
83	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
84	  });
85	  if (roleDealershipOverride) return roleDealershipOverride.effect === PermissionEffect.ALLOW;
86	
87	  const resourceDefaults = DEFAULT_PERMISSIONS[resource];
88	  if (!resourceDefaults) return false;
89	  const roleDefaults = resourceDefaults[role];
90	  if (!roleDefaults) return false;
91	  return roleDefaults.includes(action);
92	}
