19	export async function createOrderFromCart(
20	  userId: string,
21	  dealershipId: string,
22	  idempotencyKey: string
23	) {
24	  const existing = await Order.findOne({ idempotencyKey });
25	  if (existing) return existing;
26	
27	  const cart = await Cart.findOne({ userId, dealershipId }).populate('items.vehicleId');
28	  if (!cart || cart.items.length === 0) {
29	    throw new BadRequestError('Cart is empty');
30	  }
31	
32	  const groups = new Map<string, typeof cart.items>();
33	
34	  for (const item of cart.items) {
35	    const vehicle = item.vehicleId as any;
36	    const groupKey = `${vehicle.supplierId || 'default'}|${vehicle.warehouseId || 'default'}|${vehicle.estimatedTurnaround <= 1 ? 'same-day' : 'standard'}`;
37	
38	    if (!groups.has(groupKey)) {
39	      groups.set(groupKey, []);
40	    }
41	    groups.get(groupKey)!.push(item);
42	  }
43	
44	  const orders: IOrder[] = [];
45	  const session = await mongoose.startSession();
46	
47	  try {
48	    await session.withTransaction(async () => {
49	      for (const [, groupItems] of groups) {
50	        const orderItems = [];
51	        let subtotal = 0;
52	
53	        for (const item of groupItems) {
54	          const vehicle = await Vehicle.findById(item.vehicleId).session(session);
55	          if (!vehicle || vehicle.status !== VehicleStatus.AVAILABLE) {
56	            throw new BadRequestError(`Vehicle ${item.vehicleId} is no longer available`);
57	          }
58	
59	          vehicle.status = VehicleStatus.RESERVED;
60	          await vehicle.save({ session });
61	
62	          const addOnTotal = item.addOnServices.reduce((sum, a) => sum + a.price, 0);
63	          const itemSubtotal = vehicle.price + addOnTotal;
64	          subtotal += itemSubtotal;
65	
66	          orderItems.push({
67	            vehicleId: vehicle._id,
68	            supplierId: vehicle.supplierId,
69	            warehouseId: vehicle.warehouseId,
70	            turnaroundDays: vehicle.estimatedTurnaround,
71	            addOnServices: item.addOnServices,
72	            subtotal: itemSubtotal,
73	          });
74	        }
75	
76	        const orderKey = groups.size > 1 ? `${idempotencyKey}-${orders.length}` : idempotencyKey;
77	
78	        const order = new Order({
79	          orderNumber: generateOrderNumber(dealershipId),
80	          dealershipId,
81	          buyerId: userId,
82	          status: OrderStatus.CREATED,
83	          items: orderItems,
84	          totals: { subtotal, tax: 0, total: subtotal },
85	          idempotencyKey: orderKey,
86	        });
87	
88	        await order.save({ session });
89	
90	        await OrderEventModel.create(
91	          [
92	            {
93	              orderId: order._id,
94	              fromStatus: null,
95	              toStatus: OrderStatus.CREATED,
96	              triggeredBy: userId,
97	              reason: 'Order created from cart',
98	            },
99	          ],
100	          { session }
101	        );
102	
103	        orders.push(order);
104	      }
105	
106	      if (orders.length > 1) {
107	        const parentOrder = orders[0];
108	        const childIds = orders.slice(1).map((o) => o._id);
109	        for (const child of orders.slice(1)) {
110	          child.parentOrderId = parentOrder._id as any;
111	          await child.save({ session });
112	        }
113	        parentOrder.childOrderIds = childIds as any;
114	        await parentOrder.save({ session });
115	      }
116	
117	      cart.items = [];
118	      await cart.save({ session });
119	    });
120	  } finally {
121	    await session.endSession();
122	  }
123	
124	  logger.info(
125	    { orderCount: orders.length, userId, dealershipId },
126	    'Orders created from cart'
127	  );
128	
129	  return orders.length === 1 ? orders[0] : orders;
130	}
