132	export async function transitionOrder(
133	  orderId: string,
134	  event: OrderEvent,
135	  userId: string,
136	  reason: string = ''
137	) {
138	  const order = await Order.findById(orderId);
139	  if (!order) throw new NotFoundError('Order not found');
140	
141	  const fsm = createOrderStateMachine(order.status as OrderStatus);
142	
143	  if (!fsm.can(event)) {
144	    throw new BadRequestError(
145	      `Cannot apply "${event}" to order in "${order.status}" status`
146	    );
147	  }
148	
149	  const timeoutPromise = new Promise((_, reject) =>
150	    setTimeout(() => reject(new Error('Transition timeout')), 5000)
151	  );
152	
153	  const transitionPromise = (async () => {
154	    const { from, to } = await fsm.transition(event);
155	
156	    if (event === OrderEvent.CANCEL) {
157	      for (const item of order.items) {
158	        await Vehicle.findByIdAndUpdate(item.vehicleId, {
159	          status: VehicleStatus.AVAILABLE,
160	        });
161	      }
162	      order.cancelledAt = new Date();
163	      order.cancelReason = reason || 'Cancelled by user';
164	    }
165	
166	    if (event === OrderEvent.FULFILL) {
167	      for (const item of order.items) {
168	        await Vehicle.findByIdAndUpdate(item.vehicleId, {
169	          status: VehicleStatus.SOLD,
170	        });
171	      }
172	    }
173	
174	    order.status = to;
175	    await order.save();
176	
177	    await OrderEventModel.create({
178	      orderId: order._id,
179	      fromStatus: from,
180	      toStatus: to,
181	      triggeredBy: userId,
182	      reason,
183	    });
184	
185	    logger.info(
186	      { orderId, from, to, event, userId },
187	      'Order transitioned'
188	    );
189	
190	    return order;
191	  })();
192	
193	  try {
194	    return await Promise.race([transitionPromise, timeoutPromise]);
195	  } catch (error: any) {
196	    if (error.message === 'Transition timeout') {
197	      logger.error({ orderId, event }, 'Order transition timed out, rolling back');
198	      const freshOrder = await Order.findById(orderId);
199	      if (freshOrder && freshOrder.status !== order.status) {
200	        freshOrder.status = order.status as OrderStatus;
201	        await freshOrder.save();
202	      }
203	      throw new BadRequestError('Order transition timed out');
204	    }
205	    throw error;
206	  }
207	}
