1	import { Order } from '../../models/order.model';
2	import { Invoice } from '../../models/invoice.model';
3	import { Payment } from '../../models/payment.model';
4	import { ReconciliationRun } from '../../models/reconciliation-run.model';
5	import { Dealership } from '../../models/dealership.model';
6	import { OrderStatus, InvoiceStatus, PaymentStatus } from '../../types/enums';
7	import logger from '../../lib/logger';
8	
9	export async function runReconciliation() {
10	  const dealerships = await Dealership.find({ isActive: true });
11	  const results = [];
12	
13	  for (const dealership of dealerships) {
14	    try {
15	      const result = await reconcileDealership(dealership._id.toString());
16	      results.push(result);
17	    } catch (error: any) {
18	      logger.error(
19	        { dealershipId: dealership._id, error: error.message },
20	        'Reconciliation failed for dealership'
21	      );
22	      results.push(
23	        await ReconciliationRun.create({
24	          dealershipId: dealership._id,
25	          period: {
26	            from: new Date(Date.now() - 24 * 60 * 60 * 1000),
27	            to: new Date(),
28	          },
29	          status: 'failed',
30	          discrepancies: [{ type: 'error', referenceId: dealership._id, details: error.message }],
31	        })
32	      );
33	    }
34	  }
35	
36	  return results;
37	}
