39	async function reconcileDealership(dealershipId: string) {
40	  const periodEnd = new Date();
41	  periodEnd.setHours(0, 0, 0, 0);
42	  const periodStart = new Date(periodEnd.getTime() - 24 * 60 * 60 * 1000);
43	
44	  const orders = await Order.find({
45	    dealershipId,
46	    status: { $in: [OrderStatus.SETTLED, OrderStatus.FULFILLED] },
47	    updatedAt: { $gte: periodStart, $lt: periodEnd },
48	  });
49	
50	  const orderIds = orders.map((o) => o._id);
51	
52	  const invoices = await Invoice.find({
53	    dealershipId,
54	    orderId: { $in: orderIds },
55	    status: { $in: [InvoiceStatus.ISSUED, InvoiceStatus.PAID] },
56	  });
57	
58	  const invoiceIds = invoices.map((i) => i._id);
59	
60	  const payments = await Payment.find({
61	    dealershipId,
62	    invoiceId: { $in: invoiceIds },
63	    status: PaymentStatus.COMPLETED,
64	  });
65	
66	  const invoiceByOrder = new Map(invoices.map((i) => [i.orderId.toString(), i]));
67	  const paymentsByInvoice = new Map<string, typeof payments>();
68	  for (const p of payments) {
69	    const key = p.invoiceId.toString();
70	    if (!paymentsByInvoice.has(key)) paymentsByInvoice.set(key, []);
71	    paymentsByInvoice.get(key)!.push(p);
72	  }
73	
74	  const discrepancies: Array<{ type: string; referenceId: any; details: string }> = [];
75	  const unmatchedOrders: any[] = [];
76	  const unmatchedInvoices: any[] = [];
77	  const unmatchedSettlements: any[] = [];
78	  let matchedCount = 0;
79	
80	  for (const order of orders) {
81	    const invoice = invoiceByOrder.get(order._id.toString());
82	    if (!invoice) {
83	      unmatchedOrders.push(order._id);
84	      discrepancies.push({
85	        type: 'missing_invoice',
86	        referenceId: order._id,
87	        details: `Order ${order.orderNumber} has no invoice`,
88	      });
89	      continue;
90	    }
91	
92	    const orderPayments = paymentsByInvoice.get(invoice._id.toString()) || [];
93	    const paidAmount = orderPayments.reduce((sum, p) => sum + p.amount, 0);
94	
95	    if (orderPayments.length === 0) {
96	      unmatchedInvoices.push(invoice._id);
97	      discrepancies.push({
98	        type: 'unpaid_invoice',
99	        referenceId: invoice._id,
100	        details: `Invoice ${invoice.invoiceNumber} has no payments`,
101	      });
102	    } else if (paidAmount !== invoice.total) {
103	      discrepancies.push({
104	        type: 'amount_mismatch',
105	        referenceId: invoice._id,
106	        details: `Invoice ${invoice.invoiceNumber}: expected ${invoice.total}, paid ${paidAmount}`,
107	      });
108	    } else if (invoice.total !== order.totals.total) {
109	      discrepancies.push({
110	        type: 'order_invoice_mismatch',
111	        referenceId: order._id,
112	        details: `Order ${order.orderNumber} total (${order.totals.total}) != Invoice total (${invoice.total})`,
113	      });
114	    } else {
115	      matchedCount++;
116	    }
117	  }
118	
119	  const status =
120	    discrepancies.length > 0 ? 'completed_with_discrepancies' : 'completed';
121	
122	  const run = await ReconciliationRun.create({
123	    dealershipId,
124	    period: { from: periodStart, to: periodEnd },
125	    matchedCount,
126	    unmatchedOrders,
127	    unmatchedInvoices,
128	    unmatchedSettlements,
129	    discrepancies,
130	    status,
131	  });
132	
133	  logger.info(
134	    { dealershipId, matchedCount, discrepancies: discrepancies.length },
135	    'Reconciliation completed'
136	  );
137	
138	  return run;
139	}
