7	
8	interface RegisterInput {
9	  email: string;
10	  password: string;
11	  firstName: string;
12	  lastName: string;
13	  role?: string;
14	  dealershipId?: string;
15	}
16	
17	interface TokenPair {
18	  accessToken: string;
19	  refreshToken: string;
20	}
21	
22	function generateTokens(user: IUser): TokenPair {
23	  const payload = {
24	    id: user._id.toString(),
25	    email: user.email,
26	    role: user.role,
27	    dealershipId: user.dealershipId?.toString() || null,
28	  };
29	
30	  const accessToken = jwt.sign(payload, config.jwtSecret, {
31	    expiresIn: 3600,
32	  });
33	
34	  const refreshToken = jwt.sign(payload, config.jwtRefreshSecret, {
35	    expiresIn: 604800,
36	  });
37	
38	  return { accessToken, refreshToken };
39	}
40	
41	export async function register(input: RegisterInput) {
42	  const existing = await User.findOne({
43	    email: input.email,
44	    dealershipId: input.dealershipId || null,
45	  });
46	  if (existing) {
47	    throw new ConflictError('Email already registered');
48	  }
49	
50	  if (input.dealershipId) {
51	    const dealership = await Dealership.findById(input.dealershipId);
52	    if (!dealership) {
53	      throw new NotFoundError('Dealership not found');
54	    }
55	  }
56	
57	  const user = new User({
58	    email: input.email,
59	    passwordHash: input.password,
60	    role: input.role || 'buyer',
61	    dealershipId: input.dealershipId || null,
62	    profile: {
63	      firstName: input.firstName,
64	      lastName: input.lastName,
65	    },
66	  });
67	
68	  await user.save();
69	
70	  const tokens = generateTokens(user);
71	  user.refreshToken = tokens.refreshToken;
72	  await user.save();
73	
74	  logger.info({ userId: user._id, email: user.email }, 'User registered');
75	
76	  return { user: user.toJSON(), ...tokens };
77	}
78	
79	export async function login(email: string, password: string) {
80	  const user = await User.findOne({ email, isActive: true });
81	  if (!user) {
82	    throw new UnauthorizedError('Invalid email or password');
83	  }
84	
85	  const isValid = await user.comparePassword(password);
86	  if (!isValid) {
87	    throw new UnauthorizedError('Invalid email or password');
88	  }
89	
90	  const tokens = generateTokens(user);
91	  user.refreshToken = tokens.refreshToken;
92	  await user.save();
93	
94	  logger.info({ userId: user._id, email: user.email }, 'User logged in');
95	
96	  return { user: user.toJSON(), ...tokens };
97	}
98	
99	export async function refreshTokens(refreshToken: string) {
100	  try {
101	    const decoded = jwt.verify(refreshToken, config.jwtRefreshSecret) as any;
102	    const user = await User.findById(decoded.id);
103	
104	    if (!user || user.refreshToken !== refreshToken || !user.isActive) {
105	      throw new UnauthorizedError('Invalid refresh token');
106	    }
107	
108	    const tokens = generateTokens(user);
109	    user.refreshToken = tokens.refreshToken;
110	    await user.save();
111	
112	    return tokens;
113	  } catch {
114	    throw new UnauthorizedError('Invalid refresh token');
115	  }
116	}
