24	export async function searchVehicles(
25	  params: SearchParams,
26	  pagination: PaginationParams,
27	  userId?: string
28	) {
29	  const cacheParams = { ...params, ...pagination };
30	  const cached = await getCachedResult(cacheParams);
31	  if (cached) {
32	    return cached;
33	  }
34	
35	  const query: any = { status: VehicleStatus.AVAILABLE };
36	
37	  if (params.dealershipId) query.dealershipId = params.dealershipId;
38	
39	  let expandedTerms: string[] = [];
40	
41	  if (params.q) {
42	    const terms = params.q.trim().toLowerCase().split(/\s+/);
43	    const allTerms: string[] = [];
44	
45	    for (const term of terms) {
46	      const makeExpansions = await expandSynonyms(term, 'make');
47	      const modelExpansions = await expandSynonyms(term, 'model');
48	      const unique = [...new Set([...makeExpansions, ...modelExpansions])];
49	      allTerms.push(...unique);
50	    }
51	
52	    expandedTerms = allTerms;
53	
54	    const regexPatterns = allTerms.map((t) => new RegExp(t, 'i'));
55	    query.$or = [
56	      { make: { $in: regexPatterns } },
57	      { model: { $in: regexPatterns } },
58	      { description: { $in: regexPatterns } },
59	    ];
60	  }
61	
62	  if (params.make) {
63	    const makeExpansions = await expandSynonyms(params.make, 'make');
64	    const regexes = makeExpansions.map((m) => new RegExp(`^${m}$`, 'i'));
65	    query.make = { $in: regexes };
66	  }
67	
68	  if (params.model) {
69	    const modelExpansions = await expandSynonyms(params.model, 'model');
70	    const regexes = modelExpansions.map((m) => new RegExp(`^${m}$`, 'i'));
71	    query.model = { $in: regexes };
72	  }
73	
74	  if (params.year) query.year = params.year;
75	
76	  if (params.minPrice || params.maxPrice) {
77	    query.price = {};
78	    if (params.minPrice) query.price.$gte = params.minPrice;
79	    if (params.maxPrice) query.price.$lte = params.maxPrice;
80	  }
81	
82	  if (params.minMileage || params.maxMileage) {
83	    query.mileage = {};
84	    if (params.minMileage) query.mileage.$gte = params.minMileage;
85	    if (params.maxMileage) query.mileage.$lte = params.maxMileage;
86	  }
87	
88	  if (params.region) query.region = new RegExp(params.region, 'i');
89	
90	  if (params.minRegistrationDate || params.maxRegistrationDate) {
91	    query.registrationDate = {};
92	    if (params.minRegistrationDate) query.registrationDate.$gte = new Date(params.minRegistrationDate);
93	    if (params.maxRegistrationDate) query.registrationDate.$lte = new Date(params.maxRegistrationDate);
94	  }
95	
96	  const sort: any = { [pagination.sortBy]: pagination.sortOrder === 'asc' ? 1 : -1, _id: 1 };
97	  const skip = (pagination.page - 1) * pagination.limit;
98	
99	  const [data, total] = await Promise.all([
100	    Vehicle.find(query).sort(sort).skip(skip).limit(pagination.limit),
101	    Vehicle.countDocuments(query),
102	  ]);
103	
104	  const trending = await getTrendingKeywords();
105	
106	  const result = {
107	    ...buildPaginatedResult(data, total, pagination),
108	    trending: trending.slice(0, 10),
109	    expandedTerms,
110	  };
111	
112	  await setCachedResult(cacheParams, result);
113	
114	  SearchLog.create({
115	    dealershipId: params.dealershipId || null,
116	    userId: userId || null,
117	    rawQuery: params.q || '',
118	    expandedTerms,
119	    filters: params,
120	    resultCount: total,
121	  }).catch(() => {});
122	
123	  return result;
124	}
