1	export interface PaginationParams {
2	  page: number;
3	  limit: number;
4	  sortBy: string;
5	  sortOrder: 'asc' | 'desc';
6	}
7	
8	export interface PaginatedResult<T> {
9	  data: T[];
10	  pagination: {
11	    page: number;
12	    limit: number;
13	    total: number;
14	    totalPages: number;
15	    hasNext: boolean;
16	    hasPrev: boolean;
17	  };
18	}
19	
20	export function parsePaginationParams(query: any): PaginationParams {
21	  const page = Math.max(1, parseInt(query.page) || 1);
22	  const limit = Math.min(100, Math.max(1, parseInt(query.limit) || 20));
23	  const sortBy = query.sortBy || 'createdAt';
24	  const sortOrder = query.sortOrder === 'asc' ? 'asc' : 'desc';
25	  return { page, limit, sortBy, sortOrder };
26	}
27	
28	export function buildPaginatedResult<T>(
29	  data: T[],
30	  total: number,
31	  params: PaginationParams
32	): PaginatedResult<T> {
33	  const totalPages = Math.ceil(total / params.limit);
34	  return {
35	    data,
36	    pagination: {
37	      page: params.page,
38	      limit: params.limit,
39	      total,
40	      totalPages,
41	      hasNext: params.page < totalPages,
42	      hasPrev: params.page > 1,
43	    },
44	  };
45	}
