11	export async function uploadDocument(
12	  file: Express.Multer.File,
13	  metadata: {
14	    dealershipId: string;
15	    uploadedBy: string;
16	    type: string;
17	    orderId?: string;
18	    vehicleId?: string;
19	    sensitiveFlag?: boolean;
20	  }
21	) {
22	  validateFileSize(file.size);
23	
24	  let quarantined = false;
25	  let quarantineReason: string | null = null;
26	
27	  try {
28	    validateFileType(file.buffer, file.mimetype);
29	  } catch (error: any) {
30	    quarantined = true;
31	    quarantineReason = error.message;
32	  }
33	
34	  const sha256Hash = hashFile(file.buffer);
35	  const date = new Date();
36	  const subDir = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
37	
38	  let storagePath: string;
39	  if (quarantined) {
40	    const quarantineDir = path.join(config.quarantineDir, metadata.dealershipId);
41	    fs.mkdirSync(quarantineDir, { recursive: true });
42	    storagePath = path.join(quarantineDir, `${sha256Hash}-${file.originalname}`);
43	  } else {
44	    const uploadDir = path.join(config.uploadDir, metadata.dealershipId, subDir);
45	    fs.mkdirSync(uploadDir, { recursive: true });
46	    storagePath = path.join(uploadDir, `${sha256Hash}-${file.originalname}`);
47	  }
48	
49	  fs.writeFileSync(storagePath, file.buffer);
50	
51	  const doc = new DocumentModel({
52	    dealershipId: metadata.dealershipId,
53	    orderId: metadata.orderId || null,
54	    vehicleId: metadata.vehicleId || null,
55	    uploadedBy: metadata.uploadedBy,
56	    type: metadata.type,
57	    originalFilename: file.originalname,
58	    storagePath,
59	    mimeType: file.mimetype,
60	    sizeBytes: file.size,
61	    sha256Hash,
62	    quarantined,
63	    quarantineReason,
64	    sensitiveFlag: metadata.sensitiveFlag || false,
65	  });
66	
67	  await doc.save();
68	
69	  logger.info(
70	    { documentId: doc._id, quarantined, filename: file.originalname },
71	    'Document uploaded'
72	  );
73	
74	  return doc;
75	}
