83	export async function downloadDocument(documentId: string) {
84	  const doc = await DocumentModel.findById(documentId);
85	  if (!doc) throw new NotFoundError('Document not found');
86	  if (doc.quarantined) throw new ForbiddenError('Document is quarantined');
87	
88	  if (!fs.existsSync(doc.storagePath)) {
89	    throw new NotFoundError('Document file not found on disk');
90	  }
91	
92	  const buffer = fs.readFileSync(doc.storagePath);
93	  const currentHash = hashFile(buffer);
94	
95	  if (currentHash !== doc.sha256Hash) {
96	    doc.quarantined = true;
97	    doc.quarantineReason = 'Hash mismatch on download - possible tampering';
98	    await doc.save();
99	    throw new ForbiddenError('Document integrity check failed - quarantined');
100	  }
101	
102	  return { buffer, mimeType: doc.mimeType, filename: doc.originalFilename };
103	}
