9	function generateInvoiceNumber(): string {
10	  const ts = Date.now().toString(36).toUpperCase();
11	  return `INV-${ts}`;
12	}
13	
14	async function calculateTax(dealershipId: string, subtotal: number) {
15	  const dealership = await Dealership.findById(dealershipId);
16	  if (!dealership) return { taxBreakdown: [], totalTax: 0 };
17	
18	  const state = dealership.address.state;
19	  const county = dealership.address.county;
20	
21	  const taxRate = await TaxRate.findOne({
22	    state: new RegExp(`^${state}$`, 'i'),
23	    county: county ? new RegExp(`^${county}$`, 'i') : '',
24	    effectiveDate: { $lte: new Date() },
25	    $or: [{ expiresAt: null }, { expiresAt: { $gt: new Date() } }],
26	  }).sort({ effectiveDate: -1 });
27	
28	  if (!taxRate) return { taxBreakdown: [], totalTax: 0 };
29	
30	  const taxAmount = Math.round(subtotal * taxRate.rate);
31	  const taxBreakdown = [
32	    {
33	      jurisdiction: county ? `${county}, ${state}` : state,
34	      rate: taxRate.rate,
35	      amount: taxAmount,
36	    },
37	  ];
38	
39	  return { taxBreakdown, totalTax: taxAmount };
40	}
