42	export async function generateInvoicePreview(orderId: string) {
43	  const order = await Order.findById(orderId).populate('items.vehicleId');
44	  if (!order) throw new NotFoundError('Order not found');
45	
46	  const { taxBreakdown, totalTax } = await calculateTax(
47	    order.dealershipId.toString(),
48	    order.totals.subtotal
49	  );
50	
51	  const lineItems = order.items.map((item: any) => {
52	    const vehicle = item.vehicleId;
53	    const vehicleTotal = item.subtotal;
54	    const taxRate = taxBreakdown.length > 0 ? taxBreakdown[0].rate : 0;
55	    const taxAmount = Math.round(vehicleTotal * taxRate);
56	
57	    return {
58	      description: vehicle ? `${vehicle.year} ${vehicle.make} ${vehicle.model}` : 'Vehicle',
59	      quantity: 1,
60	      unitPrice: item.subtotal,
61	      taxRate,
62	      taxAmount,
63	      total: vehicleTotal + taxAmount,
64	    };
65	  });
66	
67	  return {
68	    orderId: order._id,
69	    orderNumber: order.orderNumber,
70	    lineItems,
71	    subtotal: order.totals.subtotal,
72	    taxBreakdown,
73	    total: order.totals.subtotal + totalTax,
74	    isPreview: true,
75	  };
76	}
