78	export async function createInvoice(orderId: string) {
79	  const existing = await Invoice.findOne({ orderId, isPreview: false });
80	  if (existing) return existing;
81	
82	  const preview = await generateInvoicePreview(orderId);
83	  const order = await Order.findById(orderId);
84	  if (!order) throw new NotFoundError('Order not found');
85	
86	  const invoice = new Invoice({
87	    invoiceNumber: generateInvoiceNumber(),
88	    dealershipId: order.dealershipId,
89	    orderId,
90	    lineItems: preview.lineItems,
91	    subtotal: preview.subtotal,
92	    taxBreakdown: preview.taxBreakdown,
93	    total: preview.total,
94	    status: InvoiceStatus.ISSUED,
95	    isPreview: false,
96	  });
97	
98	  await invoice.save();
99	
100	  order.totals.tax = preview.total - preview.subtotal;
101	  order.totals.total = preview.total;
102	  await order.save();
103	
104	  logger.info({ invoiceId: invoice._id, orderId }, 'Invoice created');
105	
106	  return invoice;
107	}
