{"file_path": "/home/wendirad/Work/eaglepointai/w1t22/repo/server/src/controllers/auth.controller.ts", "content": "import { Request, Response, NextFunction } from 'express';
import * as authService from '../services/auth.service';
import { logAuditEvent } from '../services/audit.service';

export async function register(req: Request, res: Response, next: NextFunction) {
  try {
    const result = await authService.register(req.body);
    await logAuditEvent({
      userId: result.user._id?.toString() || '',
      role: result.user.role || 'buyer',
      ip: req.ip || '',
      action: 'user.register',
      resourceType: 'user',
      resourceId: result.user._id?.toString() || '',
      after: { email: result.user.email, role: result.user.role },
      requestId: (req as any).requestId,
    });
    res.status(201).json(result);
  } catch (error) {
    next(error);
  }
}

export async function login(req: Request, res: Response, next: NextFunction) {
  try {
    const { email, password } = req.body;
    const result = await authService.login(email, password);
    await logAuditEvent({
      userId: result.user._id?.toString() || '',
      role: result.user.role || '',
      ip: req.ip || '',
      action: 'user.login',
      resourceType: 'user',
      resourceId: result.user._id?.toString() || '',
      requestId: (req as any).requestId,
    });
    res.json(result);
  } catch (error) {
    next(error);
  }
}

