      req.user!.id,
      req.user!.role,
      dealershipId,
      'document',
      doc._id.toString(),
      'read',
      doc.sensitiveFlag
    );

    if (!hasPermission) throw new ForbiddenError('No permission to view this document');

    res.json(doc);
  } catch (error) {
    next(error);
  }
}

