3	class InMemoryLedger {
4	  constructor() {
5	    this.balances = new Map();
6	    this.transactions = [];
7	    this.idempotencyKeys = new Set();
8	  }
9	
10	  getBalance(accountId) {
11	    return this.balances.get(accountId) || 0;
12	  }
13	
14	  recordTransaction(params) {
15	    const debitKey = `${params.idempotencyKey}-debit`;
16	    if (this.idempotencyKeys.has(debitKey)) {
17	      return this.transactions.filter((t) => t.idempotencyKey.startsWith(params.idempotencyKey));
18	    }
19	
20	    const debitBalance = this.getBalance(params.debitAccountId) - params.amount;
21	    this.balances.set(params.debitAccountId, debitBalance);
22	
23	    const creditBalance = this.getBalance(params.creditAccountId) + params.amount;
24	    this.balances.set(params.creditAccountId, creditBalance);
25	
26	    const debitTx = {
27	      accountId: params.debitAccountId,
28	      type: 'debit',
29	      amount: params.amount,
30	      balanceAfter: debitBalance,
31	      idempotencyKey: debitKey,
32	    };
33	
34	    const creditTx = {
35	      accountId: params.creditAccountId,
36	      type: 'credit',
37	      amount: params.amount,
38	      balanceAfter: creditBalance,
39	      idempotencyKey: `${params.idempotencyKey}-credit`,
40	    };
41	
42	    this.transactions.push(debitTx, creditTx);
43	    this.idempotencyKeys.add(debitKey);
44	    this.idempotencyKeys.add(`${params.idempotencyKey}-credit`);
45	
46	    return [debitTx, creditTx];
47	  }
48	}
