6	function encrypt(plaintext, key, keyVersion) {
7	  const iv = crypto.randomBytes(16);
8	  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
9	  let ciphertext = cipher.update(plaintext, 'utf8', 'hex');
10	  ciphertext += cipher.final('hex');
11	  const tag = cipher.getAuthTag();
12	  return { ciphertext, iv: iv.toString('hex'), tag: tag.toString('hex'), keyVersion };
13	}
14	
15	function decrypt(data, key) {
16	  const decipher = crypto.createDecipheriv(ALGORITHM, key, Buffer.from(data.iv, 'hex'));
17	  decipher.setAuthTag(Buffer.from(data.tag, 'hex'));
18	  let plaintext = decipher.update(data.ciphertext, 'hex', 'utf8');
19	  plaintext += decipher.final('utf8');
20	  return plaintext;
21	}
