18	function checkPermission(role, resource, action, sensitiveFlag, overrides) {
19	  if (role === 'admin') return true;
20	
21	  if (sensitiveFlag && role !== 'finance_reviewer' && role !== 'admin') {
22	    const override = overrides.find(
23	      (o) => o.effect === 'allow' && o.actions.includes(action)
24	    );
