27	
28	  for (const override of overrides) {
29	    if (override.actions.includes(action)) {
30	      return override.effect === 'allow';
31	    }
32	  }
33	
34	  const resourceDefaults = DEFAULT_PERMISSIONS[resource];
35	  if (!resourceDefaults) return false;
36	  const roleDefaults = resourceDefaults[role];
37	  if (!roleDefaults) return false;
38	  return roleDefaults.includes(action);
39	}
