3	class StateMachine {
4	  constructor(definition, currentState) {
5	    this.definition = definition;
6	    this.currentState = currentState || definition.initial;
7	  }
8	
9	  getState() { return this.currentState; }
10	
11	  can(event) {
12	    return this.definition.transitions.some(
13	      (t) => (Array.isArray(t.from) ? t.from.includes(this.currentState) : t.from === this.currentState) && t.event === event
14	    );
15	  }
16	
17	  getAvailableEvents() {
18	    return this.definition.transitions
19	      .filter((t) => Array.isArray(t.from) ? t.from.includes(this.currentState) : t.from === this.currentState)
20	      .map((t) => t.event);
21	  }
22	
23	  async transition(event, context) {
24	    const transition = this.definition.transitions.find(
25	      (t) => (Array.isArray(t.from) ? t.from.includes(this.currentState) : t.from === this.currentState) && t.event === event
26	    );
27	    if (!transition) throw new Error(`Invalid transition: cannot apply event "${event}" in state "${this.currentState}"`);
28	    if (transition.guard) {
29	      const allowed = await transition.guard(context);
30	      if (!allowed) throw new Error(`Guard rejected transition: "${event}" from "${this.currentState}"`);
31	    }
32	    const from = this.currentState;
33	    this.currentState = transition.to;
34	    return { from, to: transition.to };
35	  }
36	}
