11	function buildSynonymMap(synonyms) {
12	  const cache = new Map();
13	  for (const syn of synonyms) {
14	    if (!cache.has(syn.field)) cache.set(syn.field, new Map());
15	    const fieldMap = cache.get(syn.field);
16	    fieldMap.set(syn.canonical.toLowerCase(), syn.aliases.map((a) => a.toLowerCase()));
17	    for (const alias of syn.aliases) {
18	      fieldMap.set(alias.toLowerCase(), [syn.canonical.toLowerCase()]);
19	    }
20	  }
21	  return cache;
22	}
23	
24	function expandSynonyms(term, field, cache) {
25	  const fieldMap = cache.get(field);
26	  if (!fieldMap) return [term];
27	  const lowerTerm = term.toLowerCase();
28	  const expansions = fieldMap.get(lowerTerm);
29	  if (!expansions) return [term];
30	  return [term, ...expansions];
31	}
