23	function request(method, path, body, token) {
24	  return new Promise((resolve, reject) => {
25	    const url = new URL(path, BASE_URL);
26	    const options = {
27	      hostname: url.hostname,
28	      port: url.port,
29	      path: url.pathname + url.search,
30	      method,
31	      headers: {
32	        'Content-Type': 'application/json',
33	        'X-Timestamp': new Date().toISOString(),
34	      },
35	    };
36	
37	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
38	
39	    const req = http.request(options, (res) => {
40	      let data = '';
41	      res.on('data', (chunk) => { data += chunk; });
42	      res.on('end', () => {
43	        let parsed;
44	        try { parsed = JSON.parse(data); } catch { parsed = data; }
45	        resolve({ status: res.statusCode, data: parsed });
46	      });
47	    });
48	
49	    req.on('error', reject);
50	    if (body) req.write(JSON.stringify(body));
51	    req.end();
52	  });
53	}
