381	function waitForServer(retries = 30, delay = 2000) {
382	  return new Promise((resolve, reject) => {
383	    function attempt(n) {
384	      request('GET', '/api/v1/health')
385	        .then((res) => {
386	          if (res.status === 200) resolve();
387	          else if (n <= 0) reject(new Error('Server not ready'));
388	          else setTimeout(() => attempt(n - 1), delay);
389	        })
390	        .catch(() => {
391	          if (n <= 0) reject(new Error('Server not reachable'));
392	          else setTimeout(() => attempt(n - 1), delay);
393	        });
394	    }
395	    attempt(retries);
396	  });
397	}
