23	  (response) => response,
24	  async (error) => {
25	    if (error.response?.status === 401) {
26	      const refreshToken = localStorage.getItem('refreshToken');
27	      if (refreshToken && !error.config._retry) {
28	        error.config._retry = true;
29	        try {
30	          const { data } = await axios.post(`${API_BASE}/auth/refresh`, { refreshToken });
31	          localStorage.setItem('accessToken', data.accessToken);
32	          localStorage.setItem('refreshToken', data.refreshToken);
33	          error.config.headers.Authorization = `Bearer ${data.accessToken}`;
34	          return httpClient(error.config);
35	        } catch {
36	          localStorage.removeItem('accessToken');
37	          localStorage.removeItem('refreshToken');
38	          window.location.href = '/login';
39	        }
40	      }
41	    }
42	    return Promise.reject(error);
43	  }
44	);
