20	export async function processPayment(input: PaymentInput) {
21	  const existing = await Payment.findOne({ idempotencyKey: input.idempotencyKey });
22	  if (existing) return existing;
23	
24	  const invoice = await Invoice.findById(input.invoiceId);
25	  if (!invoice) throw new NotFoundError('Invoice not found');
26	  if (invoice.status === InvoiceStatus.PAID) {
27	    throw new BadRequestError('Invoice already paid');
28	  }
29	
30	  if (input.amount !== invoice.total) {
31	    throw new BadRequestError(
32	      `Payment amount (${input.amount}) does not match invoice total (${invoice.total})`
33	    );
34	  }
35	
36	  const order = await Order.findById(input.orderId);
37	  if (!order) throw new NotFoundError('Order not found');
38	
39	  const adapter = resolveAdapter(input.method);
40	  const adapterResult = await adapter.charge({
41	    amount: input.amount,
42	    currency: 'USD',
43	    orderId: input.orderId,
44	    invoiceId: input.invoiceId,
45	    method: input.method,
46	    metadata: input.metadata,
47	  });
48	
49	  if (!adapterResult.success) {
50	    const failedPayment = new Payment({
51	      dealershipId: input.dealershipId,
52	      orderId: input.orderId,
53	      invoiceId: input.invoiceId,
54	      method: input.method as PaymentMethod,
55	      amount: input.amount,
56	      status: PaymentStatus.FAILED,
57	      adapterUsed: adapter.name,
58	      metadata: { ...input.metadata, adapterResult },
59	      idempotencyKey: input.idempotencyKey,
60	    });
61	    await failedPayment.save();
62	    throw new BadRequestError('Payment processing failed');
63	  }
64	
65	  const payment = new Payment({
66	    dealershipId: input.dealershipId,
67	    orderId: input.orderId,
68	    invoiceId: input.invoiceId,
69	    method: input.method as PaymentMethod,
70	    amount: input.amount,
71	    status: PaymentStatus.COMPLETED,
72	    adapterUsed: adapter.name,
73	    metadata: { ...input.metadata, adapterTransactionId: adapterResult.transactionId, ...adapterResult.metadata },
74	    idempotencyKey: input.idempotencyKey,
75	  });
76	
77	  await payment.save();
78	
79	  await recordTransaction({
80	    dealershipId: input.dealershipId,
81	    debitAccountId: `buyer:${order.buyerId}`,
82	    creditAccountId: `dealership:${input.dealershipId}`,
83	    amount: input.amount,
84	    referenceType: 'payment',
85	    referenceId: payment._id.toString(),
86	    description: `Payment for order ${order.orderNumber}`,
87	    idempotencyKey: `payment-${payment._id}`,
88	  });
89	
90	  invoice.status = InvoiceStatus.PAID;
91	  await invoice.save();
92	
93	  logger.info(
94	    { paymentId: payment._id, orderId: input.orderId, amount: input.amount, method: input.method, adapter: adapter.name },
95	    'Payment processed'
96	  );
97	
98	  return payment;
99	}
