101	export async function refundPayment(paymentId: string, reason: string) {
102	  const payment = await Payment.findById(paymentId);
103	  if (!payment) throw new NotFoundError('Payment not found');
104	  if (payment.status === PaymentStatus.REFUNDED) {
105	    throw new BadRequestError('Payment already refunded');
106	  }
107	
108	  const adapter = resolveAdapter(payment.method);
109	  const adapterTransactionId = payment.metadata?.adapterTransactionId || '';
110	  const adapterResult = await adapter.refund(adapterTransactionId, payment.amount);
111	
112	  if (!adapterResult.success) {
113	    throw new BadRequestError('Refund processing failed');
114	  }
115	
116	  payment.status = PaymentStatus.REFUNDED;
117	  payment.metadata = { ...payment.metadata, refundReason: reason, refundTransactionId: adapterResult.transactionId };
118	  await payment.save();
119	
120	  const order = await Order.findById(payment.orderId);
121	
122	  await recordTransaction({
123	    dealershipId: payment.dealershipId.toString(),
124	    debitAccountId: `dealership:${payment.dealershipId}`,
125	    creditAccountId: `buyer:${order?.buyerId}`,
126	    amount: payment.amount,
127	    referenceType: 'refund',
128	    referenceId: payment._id.toString(),
129	    description: `Refund for payment ${payment._id}: ${reason}`,
130	    idempotencyKey: `refund-${payment._id}`,
131	  });
132	
133	  const invoice = await Invoice.findById(payment.invoiceId);
134	  if (invoice) {
135	    invoice.status = InvoiceStatus.VOIDED;
136	    await invoice.save();
137	  }
138	
139	  logger.info({ paymentId, amount: payment.amount, reason }, 'Payment refunded');
140	  return payment;
141	}
