42	      transactionId: `offline-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
43	      status: 'completed',
44	      metadata: { method: params.method, recordedAt: new Date().toISOString() },
45	    };
46	  }
47	
48	  async refund(transactionId: string, amount: number): Promise<PaymentAdapterResult> {
