105	export function resolveAdapter(method: string): PaymentAdapter {
106	  const adapter = adapters.find((a) => a.supports(method));
107	  if (!adapter) {
108	    throw new Error(`No payment adapter found for method: ${method}`);
109	  }
110	  return adapter;
111	}
