const SENSITIVE_PATTERNS = [
  'ssn', 'driversLicense', 'driversLicenseEncrypted', 'ssnEncrypted',
  'password', 'passwordHash', 'refreshToken', 'accessToken',
  'creditCard', 'cardNumber',
];

const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
  transport:
    process.env.NODE_ENV === 'development'
      ? { target: 'pino-pretty', options: { colorize: true } }
      : undefined,
  redact: {
    paths: SENSITIVE_PATTERNS.flatMap((field) => [
      field,
      `*.${field}`,
      `*.*.${field}`,
      `*.profile.${field}`,
    ]),
    censor: '[REDACTED]',
  },
  formatters: {
    level(label) {
      return { level: label };
    },
  },
  timestamp: pino.stdTimeFunctions.isoTime,
});

export default logger;

export function sanitizeForAudit(data: Record<string, any> | null | undefined): Record<string, any> | null {
  if (!data) return null;
  const sanitized = { ...data };
  for (const key of Object.keys(sanitized)) {
    if (SENSITIVE_PATTERNS.some((p) => key.toLowerCase().includes(p.toLowerCase()))) {
      sanitized[key] = '[REDACTED]';
    }
    if (sanitized[key] && typeof sanitized[key] === 'object' && !Array.isArray(sanitized[key])) {
      sanitized[key] = sanitizeForAudit(sanitized[key]);
    }
  }
  return sanitized;
}
"}

